sql:
SELECT style, category, color
FROM garments
ORDER BY category, style;

SELECT location_id, AVG(quantity_sold) AS avg_cargo_load
FROM sales
GROUP BY location_id;

SELECT g.garment_id, g.style, g.product_line_id, pl.product_line_name, pl.season, pl.collection
FROM garments g
JOIN product_lines pl ON g.product_line_id = pl.product_line_id;

SELECT product_line_id, product_line_name, season, collection, SIN(product_line_id) AS sine_value
FROM product_lines
WHERE product_line_id > 10;

SELECT description, launch_date
FROM product_lines
WHERE product_line_id = 'desired_id';

SELECT AVG(total_garments) AS average_garments_per_product_line 
FROM (
  SELECT product_line_id, COUNT(garment_id) AS total_garments 
  FROM garments 
  GROUP BY product_line_id
);

SELECT T1.garment_id, T1.style, T1.category, T1.description, T1.sku, T1.color, T1.size_range, T1.material, T1.target_age_group
FROM garments AS T1
JOIN inventory AS T2 ON T1.garment_id = T2.garment_id
WHERE T2.stock_quantity = (
  SELECT MAX(stock_quantity) FROM inventory
);
